import { db } from './server/db';
import { sql } from 'drizzle-orm';

async function verify\(\) {
  // 1. Soft-deleted jobs that were hard-deleted by migration
  //    \(We can't count them post-facto since they're gone, but we can check
  //     how many soft-deleted jobs remain\)
  const [remaining] = await db.execute\(sql\\`
    SELECT COUNT\(*\) AS soft_deleted_remaining
    FROM jobs
    WHERE deleted_at IS NOT NULL
  \\`\);
  console.log\('=== 1. Remaining soft-deleted jobs \(preserved due to invoice linkage\) ==='\);
  console.log\(JSON.stringify\(remaining\)\);

  // 1b. Verify all remaining soft-deleted jobs have invoice linkage
  const [noInvoiceSoftDeleted] = await db.execute\(sql\\`
    SELECT COUNT\(*\) AS orphan_soft_deleted
    FROM jobs j
    WHERE j.deleted_at IS NOT NULL
      AND j.invoice_id IS NULL
      AND NOT EXISTS \(SELECT 1 FROM invoices i WHERE i.job_id = j.id\)
  \\`\);
  console.log\('=== 1b. Soft-deleted jobs WITHOUT invoice \(should be 0\) ==='\);
  console.log\(JSON.stringify\(noInvoiceSoftDeleted\)\);

  // 2. Jobs visible on main Jobs page \(active, non-deleted\)
  const [activeJobs] = await db.execute\(sql\\`
    SELECT COUNT\(*\) AS active_jobs
    FROM jobs
    WHERE deleted_at IS NULL AND is_active = true
  \\`\);
  console.log\('=== 2. Active jobs \(main Jobs page\) ==='\);
  console.log\(JSON.stringify\(activeJobs\)\);

  // 3. Pick an affected customer company and check its jobs
  const companyCheck = await db.execute\(sql\\`
    SELECT cc.id, cc.name,
      COUNT\(j.id\) FILTER \(WHERE j.deleted_at IS NULL AND j.is_active = true\) AS visible_jobs,
      COUNT\(j.id\) FILTER \(WHERE j.deleted_at IS NOT NULL\) AS hidden_deleted_jobs
    FROM customer_companies cc
    JOIN client_locations cl ON cl.parent_company_id = cc.id
    LEFT JOIN jobs j ON j.location_id = cl.id
    GROUP BY cc.id, cc.name
    HAVING COUNT\(j.id\) > 0
    ORDER BY COUNT\(j.id\) DESC
    LIMIT 3
  \\`\);
  console.log\('=== 3. Top customer companies — visible vs hidden deleted jobs ==='\);
  for \(const row of companyCheck\) {
    console.log\(JSON.stringify\(row\)\);
  }

  // 4. Confirm no deleted jobs would appear in client/company overview
  const [deletedInOverview] = await db.execute\(sql\\`
    SELECT COUNT\(*\) AS deleted_visible
    FROM jobs j
    JOIN client_locations cl ON cl.id = j.location_id
    WHERE cl.parent_company_id IS NOT NULL
      AND \(j.deleted_at IS NOT NULL OR j.is_active = false\)
  \\`\);
  console.log\('=== 4. Deleted/inactive jobs that WOULD have appeared in old overview \(now filtered\) ==='\);
  console.log\(JSON.stringify\(deletedInOverview\)\);

  // 5. Orphaned job_visits \(visits referencing non-existent jobs\)
  const [orphanVisits] = await db.execute\(sql\\`
    SELECT COUNT\(*\) AS orphaned_visits
    FROM job_visits jv
    LEFT JOIN jobs j ON j.id = jv.job_id
    WHERE j.id IS NULL
  \\`\);
  console.log\('=== 5. Orphaned job_visits \(should be 0\) ==='\);
  console.log\(JSON.stringify\(orphanVisits\)\);

  // 6. Invoices referencing missing jobs \(financial preservation check\)
  const [danglingInvoices] = await db.execute\(sql\\`
    SELECT COUNT\(*\) AS dangling_invoices
    FROM invoices i
    WHERE i.job_id IS NOT NULL
      AND NOT EXISTS \(SELECT 1 FROM jobs j WHERE j.id = i.job_id\)
  \\`\);
  console.log\('=== 6. Invoices referencing non-existent jobs \(should be 0\) ==='\);
  console.log\(JSON.stringify\(danglingInvoices\)\);

  // 6b. Invoices referencing soft-deleted jobs \(expected — financial preservation\)
  const [invoicesOnDeletedJobs] = await db.execute\(sql\\`
    SELECT COUNT\(*\) AS invoices_on_soft_deleted_jobs
    FROM invoices i
    JOIN jobs j ON j.id = i.job_id
    WHERE j.deleted_at IS NOT NULL
  \\`\);
  console.log\('=== 6b. Invoices referencing soft-deleted jobs \(expected, preserved\) ==='\);
  console.log\(JSON.stringify\(invoicesOnDeletedJobs\)\);

  process.exit\(0\);
}

verify\(\).catch\(e => { console.error\(e\); process.exit\(1\); }\);
"
SQLEOF)
